class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 removed Discriminator property from Cosmos documents.
            // Existing docs have "Discriminator":"Blog" — re-enable it so queries still find them.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Blog");

            // Breaking change 2: EF 9 changed id format from "EntityType|KeyValue" to just "KeyValue".
            // Existing docs use "Blog|1" format — preserve it with an explicit id factory.
            entity.HasPartitionKey(b => b.Id);
            entity.Property(b => b.Id)
                .ToJsonProperty("id")
                .HasValueGenerator<BlogIdValueGenerator>();

            // Breaking change 3: Cosmos DB does not support indexing arbitrary properties.
            // HasIndex was silently ignored in EF 8 but throws in EF 9. Removed.
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

