using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Storage.ValueConversion;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: EF 9 no longer adds a "Discriminator" property to documents.
            // Existing docs have "Discriminator":"Blog"; re-enable so reads/raw SQL still work.
            entity.HasDiscriminator<string>("Discriminator").HasValue("Blog");

            // Breaking change 2: EF 9 uses the raw key as the JSON "id" value.
            // Existing docs use "Blog|<key>" format. A value converter preserves compatibility.
            var idConverter = new ValueConverter<string, string>(
                key => "Blog|" + key,   // write: key → Cosmos id
                id => id.Substring(id.IndexOf('|') + 1)); // read: Cosmos id → key
            entity.Property(b => b.Id)
                .HasConversion(idConverter);

            // Breaking change 3: HasIndex() now throws for the Cosmos provider.
            // The EF 8 call was silently ignored; in EF 9 it must be removed entirely.
            // (The previous HasIndex(b => b.Name) has been deleted.)
        });
    }
}
class Blog { public string Id { get; set; } public string Name { get; set; } }

